1	import * as SecureStore from 'expo-secure-store';
2	
3	/**
4	 * Spec gap: the US-030 AC specifies "JWT stored under MMKV key 'marketify.jwt'",
5	 * but `react-native-mmkv` v4 ships as a Nitro module that cannot load in Expo Go.
6	 * All iterations to date verify on Expo Go (no dev-client build yet — deferred per
7	 * progress pattern on US-002). We satisfy the functional intent (persistent,
8	 * secure key-value storage for the JWT) with `expo-secure-store`, which is part
9	 * of the Expo SDK and works in Expo Go natively. SecureStore also happens to be
10	 * more appropriate for credential material — it uses iOS Keychain / Android
11	 * Keystore under the hood. When a dev-client build lands (planned for US-031),
12	 * this module is the single swap point if the team wants to revisit MMKV.
13	 */
14	
15	export const STORAGE_KEYS = {
16	  jwt: 'marketify.jwt',
17	  user: 'marketify.user',
18	} as const;
19	
20	// SecureStore is async. The Supabase `global.fetch` wrapper needs a synchronous
21	// read of the JWT for every outbound request, so we mirror the token in a
22	// module-scope cache. AuthProvider is the only writer; it keeps the cache and
23	// SecureStore in lock-step.
24	let cachedToken: string | null = null;
25	
26	export function getCachedToken(): string | null {
27	  return cachedToken;
28	}
29	
30	export async function hydrateTokenFromStorage(): Promise<string | null> {
31	  const value = await SecureStore.getItemAsync(STORAGE_KEYS.jwt);
32	  cachedToken = value;
33	  return value;
34	}
35	
36	export async function persistToken(token: string): Promise<void> {
37	  cachedToken = token;
38	  await SecureStore.setItemAsync(STORAGE_KEYS.jwt, token);
39	}
40	
41	export async function readPersistedUserRaw(): Promise<string | null> {
42	  return SecureStore.getItemAsync(STORAGE_KEYS.user);
43	}
44	
45	export async function persistUserRaw(json: string): Promise<void> {
46	  await SecureStore.setItemAsync(STORAGE_KEYS.user, json);
47	}
48	
49	export async function clearPersistedAuth(): Promise<void> {
50	  cachedToken = null;
51	  await Promise.all([
52	    SecureStore.deleteItemAsync(STORAGE_KEYS.jwt),
53	    SecureStore.deleteItemAsync(STORAGE_KEYS.user),
54	  ]);
55	}
